// DefaultConcerns returns the built-in concern definitions.
func DefaultConcerns() []state.ConcernDefinition {
	concerns := make([]state.ConcernDefinition, 0, len(defaultConcernJSONs))
	for _, raw := range defaultConcernJSONs {
		var c state.ConcernDefinition
		if err := json.Unmarshal([]byte(raw), &c); err != nil {
			panic("defaults: failed to parse embedded concern JSON: " + err.Error())
		}
		concerns = append(concerns, c)
	}
	return concerns
}

// =============================================================================
// Built-in pack rule contents (source .md files live in the pack directories)
// =============================================================================

var typescriptRules = map[string]string{
	"use-strict-types": "Prefer explicit types over inference for function params and returns",
	"no-any":           "Never use 'any'. Use 'unknown' when type is genuinely unknown.",
	"prefer-const":     "Use const by default, let only when reassignment is needed",
}

var reactRules = map[string]string{
	"component-structure":        "One component per file. Name file same as component.",
	"prefer-function-components": "Use function components with hooks. No class components.",
	"state-management":           "Keep state as close to where it's used as possible.",
}

var securityRules = map[string]string{
	"no-secrets-in-code": "Never hardcode API keys, passwords, or tokens",
	"validate-input":     "Validate and sanitize all user input at API boundaries",
	"no-eval":            "Never use eval(), new Function(), or equivalent dynamic code execution",
}

// Pack manifests embedded as JSON strings.
const typescriptManifestJSON = `{"name":"typescript","version":"1.0.0","description":"TypeScript best practices","tags":["typescript","types"],"rules":["rules/use-strict-types.md","rules/no-any.md","rules/prefer-const.md"],"concerns":["concerns/ts-quality.json"]}`
const reactManifestJSON = `{"name":"react","version":"1.0.0","description":"React component conventions","tags":["react","frontend"],"rules":["rules/component-structure.md","rules/prefer-function-components.md","rules/state-management.md"]}`
const securityManifestJSON = `{"name":"security","version":"1.0.0","description":"Security audit rules","tags":["security","audit"],"rules":["rules/no-secrets-in-code.md","rules/validate-input.md","rules/no-eval.md"],"concerns":["concerns/security-audit.json"]}`

// Pack concern contents embedded as JSON strings.
const tsQualityJSON = `{"id":"ts-quality","name":"TypeScript Quality","description":"Enforces TypeScript best practices","extras":[{"questionId":"verification","text":"Does the code pass strict TypeScript checks (noEmit, strict mode)?"}],"specSections":[],"reminders":["Run tsc --noEmit before reporting task complete"],"acceptanceCriteria":["TypeScript strict mode passes with zero errors"]}`
const securityAuditJSON = `{"id":"security-audit","name":"Security Audit","description":"Security-focused review for every spec","extras":[{"questionId":"verification","text":"Has the change been reviewed for injection, XSS, CSRF, and auth bypass?"},{"questionId":"scope_boundary","text":"What security boundaries must NOT be crossed?"}],"specSections":["Security Review"],"reminders":["Check for hardcoded secrets, unsanitized input, and missing auth checks"],"acceptanceCriteria":["No hardcoded secrets","All user input validated","Auth checks present on protected routes"]}`

func mustParseConcern(raw string) state.ConcernDefinition {
	var c state.ConcernDefinition
	if err := json.Unmarshal([]byte(raw), &c); err != nil {
		panic("defaults: failed to parse embedded concern JSON: " + err.Error())
	}
	return c
}

func mustParseManifest(raw string) pack.PackManifest {
	var m pack.PackManifest
	if err := json.Unmarshal([]byte(raw), &m); err != nil {
		panic("defaults: failed to parse embedded manifest JSON: " + err.Error())
	}
	return m
}

// DefaultPacks returns the built-in pack definitions keyed by pack name.
func DefaultPacks() map[string]pack.BuiltinPack {
	typescriptPack := pack.BuiltinPack{
		Manifest:        mustParseManifest(typescriptManifestJSON),
		RuleContents:    typescriptRules,
		ConcernContents: []state.ConcernDefinition{mustParseConcern(tsQualityJSON)},
	}

	reactPack := pack.BuiltinPack{
		Manifest:        mustParseManifest(reactManifestJSON),
		RuleContents:    reactRules,
		ConcernContents: []state.ConcernDefinition{},
	}

	securityPack := pack.BuiltinPack{
		Manifest:        mustParseManifest(securityManifestJSON),
		RuleContents:    securityRules,
		ConcernContents: []state.ConcernDefinition{mustParseConcern(securityAuditJSON)},
	}

	return map[string]pack.BuiltinPack{
		"typescript": typescriptPack,
		"react":      reactPack,
		"security":   securityPack,
	}
}
